features.snippet:
module top(output logic q, input logic clk, rst_n);
  logic internal_rst;
  always_ff @(posedge clk or negedge rst_n)
    if (!rst_n) internal_rst <= 1'b0;
    else internal_rst <= 1'b1;
  always_ff @(posedge clk or negedge internal_rst)
    if (!internal_rst) q <= 1'b0;
    else q <= 1'b1;
endmodule

logic rst_out;
always_ff @(posedge clk or negedge ext_rst) begin
  if (!ext_rst) rst_out <= 1'b0;
  else rst_out <= 1'b1;
end
